-- Framework parity tables — run once, safe to re-run (IF NOT EXISTS)
CREATE TABLE IF NOT EXISTS lbi_subdomain_norms (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), age_band_code text NOT NULL, subdomain_code text NOT NULL, min_score numeric DEFAULT 0, median_score numeric DEFAULT 50, top10_score numeric DEFAULT 100, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(age_band_code, subdomain_code));
CREATE TABLE IF NOT EXISTS lbi_age_band_weights (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), age_band_code text NOT NULL, subdomain_code text NOT NULL, weight numeric DEFAULT 1.0, weight_type text DEFAULT 'core', created_at timestamptz DEFAULT now(), UNIQUE(age_band_code, subdomain_code));
CREATE TABLE IF NOT EXISTS lbi_clusters (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, name text NOT NULL, description text, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS lbi_cluster_map (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), cluster_id uuid REFERENCES lbi_clusters(id) ON DELETE CASCADE, subdomain_code text NOT NULL, UNIQUE(cluster_id, subdomain_code));
CREATE TABLE IF NOT EXISTS lbi_learning_mappings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subdomain_code text NOT NULL, level integer DEFAULT 3, action_type text, title text, resource_link text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS lbi_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), version integer NOT NULL, label text, notes text, changed_by uuid, change_summary jsonb DEFAULT '{}', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_domains (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), domain_code text UNIQUE NOT NULL, domain_name text NOT NULL, description text, icon_key text, color text, category text, weightage numeric DEFAULT 1.0, display_order integer DEFAULT 0, status text DEFAULT 'Active', is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_subdomains (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), domain_code text NOT NULL, subdomain_code text UNIQUE NOT NULL, subdomain_name text NOT NULL, description text, display_order integer DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subdomain_code text NOT NULL, item_code text UNIQUE, item_type text DEFAULT 'likert', difficulty integer DEFAULT 3, question text NOT NULL, expected_time integer DEFAULT 30, scoring_type text DEFAULT 'standard', language_code text DEFAULT 'en', is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_item_options (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), item_id uuid REFERENCES sdi_items(id) ON DELETE CASCADE, text text NOT NULL, score_value numeric DEFAULT 0, display_order integer DEFAULT 0);
CREATE TABLE IF NOT EXISTS sdi_stages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), stage_code text UNIQUE NOT NULL, stage_name text NOT NULL, min_grade text, max_grade text, description text, display_order integer DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_clusters (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, name text NOT NULL, description text, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_cluster_map (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), cluster_id uuid REFERENCES sdi_clusters(id) ON DELETE CASCADE, subdomain_code text NOT NULL, UNIQUE(cluster_id, subdomain_code));
CREATE TABLE IF NOT EXISTS sdi_subdomain_norms (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), stage_code text NOT NULL, subdomain_code text NOT NULL, min_score numeric DEFAULT 0, median_score numeric DEFAULT 50, top10_score numeric DEFAULT 100, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(stage_code, subdomain_code));
CREATE TABLE IF NOT EXISTS sdi_stage_weights (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), stage_code text NOT NULL, subdomain_code text NOT NULL, weight numeric DEFAULT 1.0, weight_type text DEFAULT 'core', created_at timestamptz DEFAULT now(), UNIQUE(stage_code, subdomain_code));
CREATE TABLE IF NOT EXISTS sdi_learning_mappings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subdomain_code text NOT NULL, level integer DEFAULT 3, action_type text, title text, resource_link text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), version integer NOT NULL, label text, notes text, changed_by uuid, change_summary jsonb DEFAULT '{}', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS sdi_user_responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid, item_id uuid REFERENCES sdi_items(id) ON DELETE SET NULL, response_value integer, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS competency_domains (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, name text NOT NULL, description text, color text, weight numeric DEFAULT 1.0, display_order integer DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS competencies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), domain_id uuid REFERENCES competency_domains(id) ON DELETE CASCADE, code text UNIQUE NOT NULL, name text NOT NULL, description text, competency_type text DEFAULT 'core', proficiency_levels jsonb DEFAULT '{}', is_active boolean DEFAULT true, display_order integer DEFAULT 0, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS competency_clusters (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, name text NOT NULL, description text, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS competency_assessment_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competency_id uuid REFERENCES competencies(id) ON DELETE CASCADE, code text UNIQUE, item_type text DEFAULT 'mcq', difficulty integer DEFAULT 3, level integer DEFAULT 3, question text NOT NULL, expected_time integer DEFAULT 60, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS competency_assessment_options (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), item_id uuid REFERENCES competency_assessment_items(id) ON DELETE CASCADE, text text NOT NULL, score_value numeric DEFAULT 0, display_order integer DEFAULT 0);
CREATE TABLE IF NOT EXISTS role_competency_weights (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), role_code text NOT NULL, competency_id uuid REFERENCES competencies(id) ON DELETE CASCADE, weight numeric DEFAULT 1.0, weight_type text DEFAULT 'core', created_at timestamptz DEFAULT now(), UNIQUE(role_code, competency_id));
CREATE TABLE IF NOT EXISTS stage_competency_norms (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), stage_code text NOT NULL, stage_name text, competency_id uuid REFERENCES competencies(id) ON DELETE CASCADE, min_score numeric DEFAULT 0, median_score numeric DEFAULT 50, top10_score numeric DEFAULT 100, created_at timestamptz DEFAULT now(), UNIQUE(stage_code, competency_id));
CREATE TABLE IF NOT EXISTS scoring_configs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text UNIQUE NOT NULL, value jsonb, description text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS concern_areas (id SERIAL PRIMARY KEY, category TEXT NOT NULL, concern_area TEXT NOT NULL, parent_worry TEXT NOT NULL, impact_on_child TEXT NOT NULL, assessment_type TEXT NOT NULL DEFAULT 'lbi', search_keywords TEXT NOT NULL DEFAULT '', services JSONB NOT NULL DEFAULT '[]', roles JSONB NOT NULL DEFAULT '[]', target_personas TEXT[] NOT NULL DEFAULT '{}', is_active BOOLEAN NOT NULL DEFAULT TRUE, sort_order INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ);
ALTER TABLE concern_areas ADD COLUMN IF NOT EXISTS target_personas TEXT[] NOT NULL DEFAULT '{}';
CREATE INDEX IF NOT EXISTS concern_areas_category_idx ON concern_areas(category);
CREATE INDEX IF NOT EXISTS concern_areas_sort_idx ON concern_areas(sort_order, id);
